import math
import random
import numpy as np

LINES = [(0, 1, 2), (3, 4, 5), (6, 7, 8), (0, 3, 6), (1, 4, 7), (2, 5, 8), (0, 4, 8), (2, 4, 6)]

class NeuralNetwork:

    def __init__(self, weights: list[list[float]], H_RANGE: int):
        self.weights = weights
        self.H_RANGE = H_RANGE

    def sigmoid(self, sum):
        return 1 / (1 + math.exp(-sum))
    
    def input_layer(self, x: list[int], W: list[list[float]]) -> list[float]:
        return np.dot(W, np.append(x, 1))
    
    def hidden_layer(self, a: list[float], W: list[list[float]]) -> list[float]:
        # returns list of activations (length is number of neurons)
        return [self.sigmoid(act) for act in np.dot(W, np.append(a, 1))]
    
    def predict(self, xs):
        a = [self.input_layer(xs, self.weights[0])]
        for i in range(2):
            a.append(self.hidden_layer(a[i], self.weights[i + 1]))
        
        if board_filled(xs):
            raise IndexError('board is filled')
        while True:
            # finds position with max value which is not filled
            max_position = a[-1].index(max(a[-1]))
            if xs[max_position] == 0:
                return max_position
            else:
                a[-1][max_position] = -9999999

    def create_child(self): # -> NeuralNetwork  (Pylance can't recognize it)
        weights_child = []
        for l in range(len(self.weights)):
            weights_child.append([])
            for n in range(len(self.weights[l])):
                weights_child[l].append([])
                for w in self.weights[l][n]:
                    weights_child[l][n].append(w + random.normalvariate(0, 0.05))
        # # 50% chance
        if random.randint(0, 1) == 0:
            if random.randint(0, 1) == 0:
                # 50% chance to add neuron
                if len(weights_child[1]) < self.H_RANGE:
                    weights_child[1].append([0] * 10)
                    for i in range(len(weights_child[2])):
                        weights_child[2][i].append(0)
            else:
                # 50% chance to remove neuron
                if len(weights_child[1]) > 2:
                    index = random.randint(0, len(weights_child[1]) - 1)
                    weights_child[1].pop(index)
                    for i in range(len(weights_child[2])):
                        weights_child[2][i].pop(index)
        return NeuralNetwork(weights_child, self.H_RANGE)
        
    
def check_winner(state: list[int]) -> int | None:
    for a, b, c in LINES:
        if state[a] == state[b] == state[c] != 0:
            return state[a]
    return None

def board_filled(state: list[int]) -> bool:
    for n in state:
        if n == 0:
            return False
    return True

def opponent_move(state: list[int], piece: int) -> int:
    if board_filled(state):
        raise ValueError('opponent cannot move; board is filled')
    
    def random_move() -> int:
        while True:
            move = random.randint(0, 8)
            if state[move] != 0:
                continue
            return move
        
    def winning_move(state: list[int], piece) -> int | None:
        for a, b, c in LINES:
            values = [state[a], state[b], state[c]]
            if values.count(piece) == 2 and values.count(0) == 1:
                return [a, b, c][values.index(0)]
        return None
    
    def open_squares_move(state: list[int], opponent_piece) -> int | None:
        for a, b, c in LINES:
            values = [state[a], state[b], state[c]]
            if values.count(0) == 2 and values.count(opponent_piece) == 1:
                possible_moves = [a, b, c]
                possible_moves.pop(values.index(opponent_piece))
                return possible_moves[random.randint(0, 1)]
        return None
        
    if random.randint(0, 9) == 0:
        return random_move()
    
    for move in (
        winning_move(state, piece),         # if next move can win, move there
        winning_move(state, -piece),        # if next move can block opponent, move there
        open_squares_move(state, piece)     # if there is a line with 2 open squares and 1 opponent piece, move to a random open square
    ):
        if move is not None:
            return move
        
    return random_move()

def show_board(state: list[int]):
    print('-------------')
    for i in range(3):
        row = [state[3*i], state[3*i + 1], state[3*i + 2]]
        formatted_row = ['X' if n == 1 else 'O' if n == -1 else ' ' for n in row]
        print(f'| {formatted_row[0]} | {formatted_row[1]} | {formatted_row[2]} |')
        print('-------------')
    print()

def run_game(nn: NeuralNetwork, show_moves: bool = False) -> int:
    state = [0] * 9
    nn_turn = True
    while not check_winner(state) and not board_filled(state):
        if nn_turn:
            state[nn.predict(state)] = 1
        else:
            state[opponent_move(state, -1)] = -1
        nn_turn = not nn_turn
        if show_moves:
            show_board(state)
    winner = check_winner(state)
    if winner is None:
        return 0
    elif winner == 1:
        return 1
    else:
        return -10
    
